// ================= CONFIG =================
const CLAUDE_API_URL =
  "https://cors-anywhere.herokuapp.com/https://api.anthropic.com/v1/messages";

// ⚠️ Use a stable model
const MODEL = "claude-3-5-sonnet-20241022";

// 🔴 HARDCODED API KEY (TEMP ONLY)
const API_KEY = "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";

// ================= CORE FUNCTION =================
async function callClaude(systemPrompt, userPrompt) {
  const response = await fetch(CLAUDE_API_URL, {
    method: "POST",
    headers: {
  "Content-Type": "application/json",
  "x-api-key": API_KEY,
  "anthropic-version": "2023-06-01",
  "anthropic-dangerous-direct-browser-access": "true"
},
    body: JSON.stringify({
      model: MODEL,
      max_tokens: 2000,
      system: systemPrompt,
      messages: [
        {
          role: "user",
          content: userPrompt,
        },
      ],
    }),
  });

  // ================= ERROR HANDLING =================
  if (!response.ok) {
    const errText = await response.text();
    throw new Error("Claude API Error: " + errText);
  }

  const data = await response.json();

  const text =
    data?.content?.find((c) => c.type === "text")?.text || "";

  if (!text) {
    throw new Error("Empty response from Claude");
  }

  // ================= STRICT JSON PARSE =================
  const clean = text
    .replace(/```json\s*/gi, "")
    .replace(/```/g, "")
    .trim();

  try {
    return JSON.parse(clean);
  } catch (err) {
    console.error("Raw Claude output:", text);
    throw new Error("Invalid JSON returned by Claude");
  }
}

